import React,{Component} from 'react';
import './App.css';
import Hander from './components/hander/hander'
import Left from './components/left/left'


export class App extends Component {


  constructor(props) {
    super(props);
      this.state = {
        appWidth:"100%",
        appHeight:"100vh"
      }
    }
  render() {

    return (
      <div style={{width:this.state.appWidth,height:this.state.appHeight,backgroundColor:"red"}}>
        <Hander></Hander>
        <Left></Left>
      </div>
    );
  }
}

export default App;
