import React,{Component} from 'react';
import './left.css';

export class Left extends Component {
	constructor(props) {
		super(props);
		this.state = {
			leftHeight: "auto"
		}
	}
	componentDidMount() {
		window.addEventListener('resize', this.handleResize.bind(this))

	}

	componentWillUnmount() {
		window.removeEventListener('resize', this.handleResize.bind(this))

	}



	handleResize = e => {
		this.setState({ leftHeight: e.currentTarget.innerHeight - 50});
	}

	render() {
		return (
			<div className="left" style={{ height: this.state.leftHeight, width: 300 }}>
				<div style={{ height: 500, width: 300 }}> DSADAS</div>
				<div style={{ height: 500, width: 300 }}></div>
			</div>
		);
	}
}

export default Left;